import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { payrollAPI, employeesAPI, aiAgentsAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Badge, Tabs, toast,
} from '../components/ui';
import { FileText, Plus, Check } from 'lucide-react';
import { Select } from '../components/ui';
const fmt = (n) => `₹${Number(n || 0).toLocaleString('en-IN')}`;

export default function Payroll() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('my');
  const [myPayslips, setMyPayslips] = useState([]);
  const [allPayslips, setAllPayslips] = useState([]);
  const [employeesList, setEmployeesList] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showGenerate, setShowGenerate] = useState(false);
  const [showStructure, setShowStructure] = useState(false);
  const [structForm, setStructForm] = useState({
    employee_id: '', basic_salary: '', hra: '', ta: '', da: '',
    other_allowances: '', pf_deduction: '', professional_tax: '', tds_rate: ''
  });
  const [showDetail, setShowDetail] = useState(null);
  const [generating, setGenerating] = useState(false);
  const [genForm, setGenForm] = useState({ employee_id: '', month: '', year: '' });

  const [aiLoading, setAiLoading] = useState(false);
  const [aiExplanation, setAiExplanation] = useState('');

  const canManage = hasRole('hr', 'accountant');
  const isHR = hasRole('hr', 'admin');
  const isAccountant = hasRole('accountant', 'admin');

  const tabs = [
    { key: 'my', label: 'My Payslips' },
    ...(canManage ? [{ key: 'all', label: 'All Payslips' }] : []),
  ];

  const loadData = async () => {
    setLoading(true);
    try {
      const { data } = await payrollAPI.myPayslips();
      setMyPayslips(data);

      if (canManage) {
        const [{ data: all }, { data: emps }] = await Promise.all([
          payrollAPI.allPayslips({}),
          employeesAPI.list()
        ]);
        setAllPayslips(all);
        setEmployeesList(emps || []);
      }
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to load payslips', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { loadData(); }, []);

  const handleGenerate = async (e) => {
    e.preventDefault();
    setGenerating(true);
    try {
      await payrollAPI.generate({
        employee_id: parseInt(genForm.employee_id),
        month: parseInt(genForm.month),
        year: parseInt(genForm.year),
      });
      toast('Payslip generated successfully', 'success');
      setShowGenerate(false);
      setGenForm({ employee_id: '', month: '', year: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to generate payslip', 'error');
    } finally {
      setGenerating(false);
    }
  };

  const handleSetStructure = async (e) => {
    e.preventDefault();
    setGenerating(true);
    try {
      const empId = parseInt(structForm.employee_id);
      await payrollAPI.setSalary(empId, {
        basic_salary: parseFloat(structForm.basic_salary) || 0,
        hra: parseFloat(structForm.hra) || 0,
        ta: parseFloat(structForm.ta) || 0,
        da: parseFloat(structForm.da) || 0,
        other_allowances: parseFloat(structForm.other_allowances) || 0,
        pf_deduction: parseFloat(structForm.pf_deduction) || 0,
        professional_tax: parseFloat(structForm.professional_tax) || 0,
        tds_rate: parseFloat(structForm.tds_rate) || 0,
      });
      toast('Salary structure mapped successfully', 'success');
      setShowStructure(false);
      setStructForm({
        employee_id: '', basic_salary: '', hra: '', ta: '', da: '',
        other_allowances: '', pf_deduction: '', professional_tax: '', tds_rate: ''
      });
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to update salary framework', 'error');
    } finally {
      setGenerating(false);
    }
  };

  const handleFinalize = async (id) => {
    try {
      await payrollAPI.finalize(id);
      toast('Payslip finalized', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to finalize', 'error');
    }
  };

  const handleExplainPayslip = async () => {
    setAiLoading(true);
    setAiExplanation('');
    try {
      const { data } = await aiAgentsAPI.explainPayslip({
        employee_id: showDetail.employee_id,
        month: showDetail.month,
        year: showDetail.year,
      });
      setAiExplanation(data.result);
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to analyze payslip logic', 'error');
    } finally {
      setAiLoading(false);
    }
  };

  const payslipCols = [
    {
      key: 'month', label: 'Period', render: (r) => {
        const mn = new Date(2000, (r.month || 1) - 1).toLocaleString('en', { month: 'short' });
        return <span style={{ fontWeight: 500 }}>{mn} {r.year}</span>;
      }
    },
    { key: 'gross_salary', label: 'Gross', render: (r) => fmt(r.gross_salary) },
    {
      key: 'total_deductions', label: 'Deductions', render: (r) => (
        <span style={{ color: 'var(--danger)' }}>{fmt(r.total_deductions)}</span>
      )
    },
    {
      key: 'net_pay', label: 'Net Pay', render: (r) => (
        <span style={{ fontWeight: 700, color: 'var(--success)' }}>{fmt(r.net_pay)}</span>
      )
    },
    {
      key: 'status', label: 'Status', render: (r) => (
        <Badge variant={r.status === 'finalized' ? 'success' : 'warning'}>
          {r.status === 'finalized' ? 'Finalized' : 'Draft'}
        </Badge>
      )
    },
    {
      key: 'actions', label: '', render: (r) => (
        <Btn variant="ghost" size="xs" onClick={() => setShowDetail(r)}>
          <FileText size={14} /> View
        </Btn>
      )
    },
  ];

  const allCols = [
    { key: 'employee_id', label: 'Emp ID' },
    ...payslipCols.slice(0, -1),
    {
      key: 'fin', label: '', render: (r) => (
        <div style={{ display: 'flex', gap: 6 }}>
          <Btn variant="ghost" size="xs" onClick={() => setShowDetail(r)}>
            <FileText size={14} />
          </Btn>
          {isAccountant && r.status === 'draft' && (
            <Btn variant="success" size="xs" onClick={() => handleFinalize(r.id)}>
              <Check size={13} /> Finalize
            </Btn>
          )}
        </div>
      )
    },
  ];

  return (
    <>
      <PageHeader
        title="Payroll"
        subtitle="View payslips and manage payroll"
      />

      <Card style={{ padding: 0, overflow: 'hidden' }}>
        <div style={{ padding: '16px 20px 0' }}>
          <Tabs tabs={tabs} active={tab} onChange={setTab} />
        </div>
        {tab === 'my' && (
          <Table cols={payslipCols} rows={myPayslips} loading={loading} emptyMsg="No payslips found" />
        )}
        {tab === 'all' && (
          <>
            <div style={{ display: 'flex', justifyContent: 'flex-end', marginBottom: 12, padding: '0 20px', gap: '8px' }}>
              {canManage && (
                <>
                  {isHR && (
                    <Btn size="sm" variant="secondary" onClick={() => setShowStructure(true)}>
                      Set Structure
                    </Btn>
                  )}
                  {isAccountant && (
                    <Btn size="sm" onClick={() => setShowGenerate(true)}>
                      <Plus size={16} /> Generate Payslip
                    </Btn>
                  )}
                </>
              )}
            </div>
            <Table cols={allCols} rows={allPayslips} loading={loading} emptyMsg="No payslips found" />
          </>
        )}
      </Card>

      {/* Generate Modal */}
      <Modal open={showGenerate} onClose={() => setShowGenerate(false)} title="Generate Payslip" width={420}>
        <form onSubmit={handleGenerate}>
          <Select
            label="Select Employee"
            value={genForm.employee_id}
            onChange={(e) => setGenForm({ ...genForm, employee_id: e.target.value })}
            required
            id="gen-emp-id"
          >
            <option value="">-- Choose Employee --</option>
            {employeesList.map(e => (
              <option key={e.id} value={e.employee_id}>{e.first_name} {e.last_name} ({e.employee_id})</option>
            ))}
          </Select>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Input
              label="Month"
              type="number"
              min="1"
              max="12"
              value={genForm.month}
              onChange={(e) => setGenForm({ ...genForm, month: e.target.value })}
              required
              id="gen-month"
            />
            <Input
              label="Year"
              type="number"
              min="2020"
              value={genForm.year}
              onChange={(e) => setGenForm({ ...genForm, year: e.target.value })}
              required
              id="gen-year"
            />
          </div>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowGenerate(false)}>Cancel</Btn>
            <Btn type="submit" loading={generating}>Generate</Btn>
          </div>
        </form>
      </Modal>

      {/* Set Salary Structure Modal */}
      <Modal open={showStructure} onClose={() => setShowStructure(false)} title="Define Salary Structure" width={600}>
        <form onSubmit={handleSetStructure}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 16px' }}>
            <Select
              label="Select Employee"
              required
              value={structForm.employee_id}
              onChange={async (e) => {
                const epId = e.target.value;
                setStructForm({ ...structForm, employee_id: epId });
                if (epId) {
                  try {
                    const res = await payrollAPI.getSalary(epId);
                    if (res.data) setStructForm(res.data);
                  } catch (err) {
                    // Reset fields if none exist
                    setStructForm({
                      employee_id: epId, basic_salary: '', hra: '', ta: '', da: '',
                      other_allowances: '', pf_deduction: '', professional_tax: '', tds_rate: ''
                    });
                  }
                }
              }}
              id="struct-emp"
            >
              <option value="">-- Choose Employee --</option>
              {employeesList.map(emp => (
                <option key={emp.id} value={emp.employee_id}>{emp.first_name} {emp.last_name} ({emp.employee_id})</option>
              ))}
            </Select>
            <Input label="Basic Salary (₹)" type="number" step="0.01" required value={structForm.basic_salary} onChange={(e) => setStructForm({ ...structForm, basic_salary: e.target.value })} id="struct-basic" />

            <Input label="HRA (₹)" type="number" step="0.01" value={structForm.hra} onChange={(e) => setStructForm({ ...structForm, hra: e.target.value })} id="struct-hra" />
            <Input label="TA (₹)" type="number" step="0.01" value={structForm.ta} onChange={(e) => setStructForm({ ...structForm, ta: e.target.value })} id="struct-ta" />

            <Input label="DA (₹)" type="number" step="0.01" value={structForm.da} onChange={(e) => setStructForm({ ...structForm, da: e.target.value })} id="struct-da" />
            <Input label="Other Allowances (₹)" type="number" step="0.01" value={structForm.other_allowances} onChange={(e) => setStructForm({ ...structForm, other_allowances: e.target.value })} id="struct-other" />

            <Input label="PF Deduction (₹)" type="number" step="0.01" value={structForm.pf_deduction} onChange={(e) => setStructForm({ ...structForm, pf_deduction: e.target.value })} id="struct-pf" />
            <Input label="Professional Tax (₹)" type="number" step="0.01" value={structForm.professional_tax} onChange={(e) => setStructForm({ ...structForm, professional_tax: e.target.value })} id="struct-pt" />

            <Input label="TDS Rate (%)" type="number" step="0.01" min="0" max="100" value={structForm.tds_rate} onChange={(e) => setStructForm({ ...structForm, tds_rate: e.target.value })} id="struct-tds" />
          </div>
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 12 }}>
            <Btn variant="secondary" type="button" onClick={() => setShowStructure(false)}>Cancel</Btn>
            <Btn type="submit" loading={generating}>Save Structure</Btn>
          </div>
        </form>
      </Modal>

      {/* Payslip Detail Modal */}
      <Modal open={!!showDetail} onClose={() => { setShowDetail(null); setAiExplanation(''); }} title="Payslip Details" width={500}>
        {showDetail && (
          <div>
            <div
              style={{
                textAlign: 'center',
                marginBottom: 20,
                paddingBottom: 16,
                borderBottom: '1px solid var(--border-color)',
              }}
            >
              <h3 style={{ fontSize: 18, marginBottom: 4 }}>
                {new Date(2000, (showDetail.month || 1) - 1).toLocaleString('en', { month: 'long' })} {showDetail.year}
              </h3>
              <Badge variant={showDetail.status === 'finalized' ? 'success' : 'warning'}>
                {showDetail.status}
              </Badge>
            </div>

            <div
              style={{
                background: 'var(--gray-100)',
                borderRadius: '10px',
                padding: 20,
              }}
            >
              <h4 style={{ fontSize: 12, color: 'var(--gray-500)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 12 }}>
                Earnings
              </h4>
              {[
                ['Basic Salary', showDetail.basic_salary],
                ['HRA', showDetail.hra],
                ['Transport Allowance', showDetail.ta],
                ['DA', showDetail.da],
                ['Other Allowances', showDetail.other_allowances],
                ['Gross Salary', showDetail.gross_salary],
              ].map(([label, val]) => (
                <div
                  key={label}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    padding: '7px 0',
                    fontSize: 14,
                    borderBottom: label === 'Gross Salary' ? '2px solid var(--border-color)' : '1px solid var(--gray-200)',
                    fontWeight: label === 'Gross Salary' ? 700 : 400,
                  }}
                >
                  <span style={{ color: 'var(--text-light)' }}>{label}</span>
                  <span>{fmt(val)}</span>
                </div>
              ))}

              <h4 style={{ fontSize: 12, color: 'var(--gray-500)', textTransform: 'uppercase', letterSpacing: '0.06em', marginTop: 16, marginBottom: 12 }}>
                Deductions
              </h4>
              {[
                ['Absent Days Deduction', showDetail.absent_deduction],
                ['PF Deduction', showDetail.pf_deduction],
                ['Professional Tax', showDetail.professional_tax],
                ['TDS', showDetail.tds_deduction],
                ['Total Deductions', showDetail.total_deductions],
              ].map(([label, val]) => (
                <div
                  key={label}
                  style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    padding: '7px 0',
                    fontSize: 14,
                    borderBottom: label === 'Total Deductions' ? '2px solid var(--border-color)' : '1px solid var(--gray-200)',
                    fontWeight: label === 'Total Deductions' ? 700 : 400,
                    color: label === 'Total Deductions' ? 'var(--danger)' : 'inherit',
                  }}
                >
                  <span style={{ color: 'var(--text-light)' }}>{label}</span>
                  <span>{fmt(val)}</span>
                </div>
              ))}

              <div
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  padding: '14px 0 4px',
                  fontSize: 18,
                  fontWeight: 700,
                  color: 'var(--success)',
                }}
              >
                <span>Net Pay</span>
                <span>{fmt(showDetail.net_pay)}</span>
              </div>
            </div>

            {/* AI Integration */}
            <div style={{ marginTop: 20 }}>
              <Btn variant="outline" size="sm" onClick={handleExplainPayslip} loading={aiLoading} style={{ width: '100%', display: 'flex', justifyContent: 'center' }}>
                <span style={{ marginRight: 6 }}>✨</span> AI Explain Payslip Logic
              </Btn>
              {aiExplanation && (
                <div style={{ padding: '16px', background: '#f8fafc', borderRadius: 8, marginTop: 12, border: '1px solid #e2e8f0', fontSize: 13, color: '#334155', lineHeight: 1.6, whiteSpace: 'pre-wrap' }}>
                  {aiExplanation}
                </div>
              )}
            </div>
          </div>
        )}
      </Modal>
    </>
  );
}
